        // This will produce the sequence: [1, 1, 2, 3, 5, 8, 13, 21, ...]
        // The bug causes the spiral to start with larger radii, making it look distorted.
        function fibonacciBuggy(n) {
            if (n === 0) return 1;  // Buggy base case: Should be 0
            if (n === 1) return 1;  // Correct base case, but the prior one throws it off
            return fibonacciBuggy(n - 1) + fibonacciBuggy(n - 2);
