<body>
    <h1>Fibonacci Spiral Debugging</h1>
    <p>
        This demo shows a "buggy" Fibonacci spiral (with incorrect base cases in the Fibonacci function) 
        versus a corrected one. The bug causes the spiral to be improperly sized, but it's not an issue 
        with the canvas API—it's a coding error in how the Fibonacci sequence is generated.
    </p>
    <p>
        <strong>Bug Description:</strong> In the buggy version, the Fibonacci sequence starts with [2, 3] 
        instead of [1, 1], leading to larger and offset arcs. The corrected version uses the proper 
        sequence [1, 1, 2, 3, 5, ...].
    </p>
    <div class="canvas-container">
        <div>
            <h2>Buggy Spiral (Incorrect Base Cases)</h2>
            <canvas id="buggyCanvas" width="400" height="400"></canvas>
        </div>
        <div>
            <h2>Corrected Spiral (Proper Fibonacci Sequence)</h2>
            <canvas id="correctCanvas" width="400" height="400"></canvas>
        </div>
    </div>
    <button id="drawButton">Redraw Spirals</button>

    <script>
        // Correct Fibonacci function (iterative)
        function correctFib(n) {
            if (n <= 1) return n;  // Base cases: fib(0) = 0, fib(1) = 1
            let a = 0, b = 1;
            for (let i = 2; i <= n; i++) {
                let c = a + b;
                a = b;
                b = c;
            }
            return b;
        }

        // Generate correct Fibonacci sizes array (e.g., [1, 1, 2, 3, 5, 8, ...] up to n terms)
        function getCorrectSizes(n) {
            let sizes = [];
            for (let i = 1; i <= n; i++) {  // Start from fib(1) for the spiral
                sizes.push(correctFib(i));
            }
            return sizes;  // Returns [1, 1, 2, 3, 5, 8, 13, 21]
        }

        // Buggy Fibonacci sizes array (starts with wrong base cases: [2, 3, 5, 8, ...])
        function getBuggySizes(n) {
            let sizes = [2, 3];  // Incorrect base cases: starts with 2 and 3 instead of 1 and 1
            let a = 2, b = 3;    // This mimics a flawed implementation
            for (let i = 3; i <= n; i++) {
                let c = a + b;
                sizes.push(c);
                a = b;
                b = c;
            }
            return sizes;  // Returns [2, 3, 5, 8, 13, 21, 34, 55] for n=8
        }

        // Function to draw the spiral on a given canvas using the provided sizes array
        function drawSpiral(canvasId, sizes) {
            const canvas = document.getElementById(canvasId);
            const ctx = canvas.getContext('2d');
            ctx.clearRect(0, 0, canvas.width, canvas.height);  // Clear the canvas

            const centerX = canvas.width / 2;
            const centerY = canvas.height / 2;
            let currentRadius = 0;
            let startAngle = 0;  // Start angle for each arc

            ctx.beginPath();
            ctx.strokeStyle = 'blue';  // Color for the spiral
            ctx.lineWidth = 2;

            for (let i = 0; i < sizes.length; i++) {
                currentRadius += sizes[i] * 5;  // Scale up for visibility (adjust as needed)
                ctx.arc(centerX, centerY, currentRadius, startAngle, startAngle + (Math.PI / 2));
                startAngle += Math.PI / 2;  // Rotate for the next quarter-circle
            }
            ctx.stroke();  // Draw the path
        }

        // Initial draw on page load
        window.onload = function() {
            const buggySizes = getBuggySizes(8);  // Generate 8 terms for buggy spiral
            const correctSizes = getCorrectSizes(8);  // Generate 8 terms for correct spiral
            drawSpiral('buggyCanvas', buggySizes);
            drawSpiral('correctCanvas', correctSizes);
        };

        // Button to redraw
        document.getElementById('drawButton').addEventListener('click', function() {
            const buggySizes = getBuggySizes(8);
            const correctSizes = getCorrectSizes(8);
            drawSpiral('buggyCanvas', buggySizes);
